create table wuwa_substat_value
(
	id integer generated by default as identity
		constraint wuwa_substat_value_pk
			primary key,
	substat_number integer,
	value_number integer,
	value_desc varchar(8),
	value_desc_full varchar(20)
);

comment on table wuwa_substat_value is '鸣潮 声骸 副词条 数值档位';

comment on column wuwa_substat_value.substat_number is '副词条的编号：0~12';

comment on column wuwa_substat_value.value_number is '数值档位：0~7或0~3';

comment on column wuwa_substat_value.value_desc is '数值档位描述：百分比% 或 固定值+';

alter table wuwa_substat_value owner to icehe;

create unique index wuwa_substat_value_substat_number_value_number_uindex
	on wuwa_substat_value (substat_number, value_number);

